import{_ as a,o as e,c as i,a2 as s}from"./chunks/framework.B8zgMDLd.js";const p=JSON.parse('{"title":"Vaults","description":"","frontmatter":{},"headers":[],"relativePath":"concepts/vaults.md","filePath":"concepts/vaults.md"}'),l={name:"concepts/vaults.md"};function o(r,t,n,d,c,h){return e(),i("div",null,[...t[0]||(t[0]=[s('<h1 id="vaults" tabindex="-1">Vaults <a class="header-anchor" href="#vaults" aria-label="Permalink to &quot;Vaults&quot;">​</a></h1><p>A vault is the folder Tolaria reads and writes. The filesystem is the source of truth; the app state and cache are derived from files.</p><h2 id="core-rules" tabindex="-1">Core Rules <a class="header-anchor" href="#core-rules" aria-label="Permalink to &quot;Core Rules&quot;">​</a></h2><ul><li>Notes are Markdown files.</li><li>YAML frontmatter provides structure.</li><li>Attachments are normal files inside the vault.</li><li>Type definitions and saved views are also files.</li><li>Git can track history and support remote sync.</li></ul><h2 id="why-local-files-matter" tabindex="-1">Why Local Files Matter <a class="header-anchor" href="#why-local-files-matter" aria-label="Permalink to &quot;Why Local Files Matter&quot;">​</a></h2><p>Local files keep your notes inspectable. You can open them in another editor, search with command-line tools, back them up with your own system, and version them with Git.</p><p>Tolaria should never become the only way to read your data.</p><h2 id="git-is-a-capability" tabindex="-1">Git Is A Capability <a class="header-anchor" href="#git-is-a-capability" aria-label="Permalink to &quot;Git Is A Capability&quot;">​</a></h2><p>A plain folder of Markdown files can open as a vault. Git-backed vaults unlock history, changes, commits, pull, push, conflict handling, and remote setup.</p><p>If a folder is not a Git repository, Tolaria can initialize Git when you explicitly ask it to. It avoids initializing broad personal folders such as Desktop, Documents, or Downloads unless they are clearly dedicated vault folders.</p><h2 id="app-state-versus-vault-state" tabindex="-1">App State Versus Vault State <a class="header-anchor" href="#app-state-versus-vault-state" aria-label="Permalink to &quot;App State Versus Vault State&quot;">​</a></h2><p>Vault-level information should travel with the vault. Machine-specific preferences stay with the app installation.</p><table tabindex="0"><thead><tr><th>Vault state</th><th>App state</th></tr></thead><tbody><tr><td>Type icons and colors</td><td>Editor zoom</td></tr><tr><td>Saved views</td><td>Window size</td></tr><tr><td>Pinned properties</td><td>Recent vault list</td></tr><tr><td>Relationship conventions</td><td>Local cache</td></tr><tr><td>Vault AI guidance files</td><td>AI target selection</td></tr></tbody></table>',13)])])}const f=a(l,[["render",o]]);export{p as __pageData,f as default};
